class Solution {
public:
    int findMostBookedRoom(int totalRooms, vector<vector<int>>& meetings) {
        sort(meetings.begin(), meetings.end());

        priority_queue<int, vector<int>, greater<int>> freeRooms;
        for (int i = 0; i < totalRooms; i++) {
            freeRooms.push(i);
        }

        priority_queue<pair<long long, int>,
                       vector<pair<long long, int>>,
                       greater<pair<long long, int>>> busyRooms;

        vector<long long> count(totalRooms, 0);

        for (auto &m : meetings) {
            long long start = m[0];
            long long end = m[1];
            long long duration = end - start;

            while (!busyRooms.empty() && busyRooms.top().first <= start) {
                freeRooms.push(busyRooms.top().second);
                busyRooms.pop();
            }

            if (!freeRooms.empty()) {
                int room = freeRooms.top();
                freeRooms.pop();
                busyRooms.push({end, room});
                count[room]++;
            } else {
                auto [freeTime, room] = busyRooms.top();
                busyRooms.pop();
                busyRooms.push({freeTime + duration, room});
                count[room]++;
            }
        }

        int ans = 0;
        for (int i = 1; i < totalRooms; i++) {
            if (count[i] > count[ans]) {
                ans = i;
            }
        }
        return ans;
    }
};

