// -------- Structures --------
typedef struct {
    long long time;
    int room;
} Pair;

// -------- Global Heaps --------
int freeHeap[MAXN];
int freeSize;

Pair busyHeap[MAXN];
int busySize;

// -------- Comparator for Pair --------
int cmpPair(Pair a, Pair b) {
    if (a.time != b.time) return a.time < b.time;
    return a.room < b.room;
}

// -------- Free Rooms Heap (min-heap) --------
void pushFree(int x) {
    int i = freeSize++;
    freeHeap[i] = x;

    while (i > 0) {
        int p = (i - 1) / 2;
        if (freeHeap[p] <= freeHeap[i]) break;

        int tmp = freeHeap[p];
        freeHeap[p] = freeHeap[i];
        freeHeap[i] = tmp;
        i = p;
    }
}

int popFree() {
    int res = freeHeap[0];
    freeHeap[0] = freeHeap[--freeSize];

    int i = 0;
    while (1) {
        int l = 2 * i + 1, r = 2 * i + 2, smallest = i;

        if (l < freeSize && freeHeap[l] < freeHeap[smallest])
            smallest = l;

        if (r < freeSize && freeHeap[r] < freeHeap[smallest])
            smallest = r;

        if (smallest == i) break;

        int tmp = freeHeap[i];
        freeHeap[i] = freeHeap[smallest];
        freeHeap[smallest] = tmp;
        i = smallest;
    }
    return res;
}

// -------- Busy Rooms Heap (min-heap with tie-breaking) --------
void pushBusy(long long t, int r) {
    int i = busySize++;
    busyHeap[i].time = t;
    busyHeap[i].room = r;

    while (i > 0) {
        int p = (i - 1) / 2;

        if (cmpPair(busyHeap[p], busyHeap[i])) break;

        Pair tmp = busyHeap[p];
        busyHeap[p] = busyHeap[i];
        busyHeap[i] = tmp;
        i = p;
    }
}

Pair popBusy() {
    Pair res = busyHeap[0];
    busyHeap[0] = busyHeap[--busySize];

    int i = 0;
    while (1) {
        int l = 2 * i + 1, r = 2 * i + 2, smallest = i;

        if (l < busySize && !cmpPair(busyHeap[smallest], busyHeap[l]))
            smallest = l;

        if (r < busySize && !cmpPair(busyHeap[smallest], busyHeap[r]))
            smallest = r;

        if (smallest == i) break;

        Pair tmp = busyHeap[i];
        busyHeap[i] = busyHeap[smallest];
        busyHeap[smallest] = tmp;
        i = smallest;
    }
    return res;
}

Pair topBusy() {
    return busyHeap[0];
}

// -------- Sorting meetings --------
int cmpMeet(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    if (x[0] != y[0]) return x[0] - y[0];
    return x[1] - y[1];
}

int findMostBookedRoom(int totalRooms, int meetings[][2], int mSize) {
    qsort(meetings, mSize, sizeof(meetings[0]), cmpMeet);

    freeSize = 0;
    busySize = 0;

    for (int i = 0; i < totalRooms; i++)
        pushFree(i);

    static long long count[MAXN];
    for (int i = 0; i < totalRooms; i++)
        count[i] = 0;

    for (int i = 0; i < mSize; i++) {
        long long start = meetings[i][0];
        long long end = meetings[i][1];
        long long duration = end - start;

        while (busySize > 0 && topBusy().time <= start) {
            Pair p = popBusy();
            pushFree(p.room);
        }

        if (freeSize > 0) {
            int room = popFree();
            pushBusy(end, room);
            count[room]++;
        } else {
            Pair p = popBusy();
            pushBusy(p.time + duration, p.room);
            count[p.room]++;
        }
    }

    int ans = 0;
    for (int i = 1; i < totalRooms; i++) {
        if (count[i] > count[ans])
            ans = i;
    }
    return ans;
}

