class Solution {

    public int findMostBookedRoom(int totalRooms, List<int[]> meetings) {
        // Sort meetings by start time
        meetings.sort(Comparator.comparingInt(a -> a[0]));

        // Min-heap of available rooms
        PriorityQueue<Integer> freeRooms = new PriorityQueue<>();
        for (int i = 0; i < totalRooms; i++) {
            freeRooms.offer(i);
        }

        // Min-heap of busy rooms: (endTime, roomNumber)
        PriorityQueue<long[]> busyRooms = new PriorityQueue<>(
            (a, b) -> a[0] == b[0] ? Long.compare(a[1], b[1]) : Long.compare(a[0], b[0])
        );

        long[] roomCount = new long[totalRooms];

        for (int[] meeting : meetings) {
            long start = meeting[0];
            long end = meeting[1];
            long duration = end - start;

            // Free rooms that are available by start time
            while (!busyRooms.isEmpty() && busyRooms.peek()[0] <= start) {
                freeRooms.offer((int) busyRooms.poll()[1]);
            }

            if (!freeRooms.isEmpty()) {
                int room = freeRooms.poll();
                busyRooms.offer(new long[]{end, room});
                roomCount[room]++;
            } else {
                long[] earliest = busyRooms.poll();
                long freeTime = earliest[0];
                int room = (int) earliest[1];
                busyRooms.offer(new long[]{freeTime + duration, room});
                roomCount[room]++;
            }
        }

        int ans = 0;
        for (int i = 1; i < totalRooms; i++) {
            if (roomCount[i] > roomCount[ans]) {
                ans = i;
            }
        }
        return ans;
    }
}

