class MinHeap {
    constructor(compare) {
        this.data = [];
        this.compare = compare;
    }

    size() {
        return this.data.length;
    }

    peek() {
        return this.data[0];
    }

    push(val) {
        this.data.push(val);
        this._heapifyUp();
    }

    pop() {
        if (this.size() === 1) return this.data.pop();
        const root = this.data[0];
        this.data[0] = this.data.pop();
        this._heapifyDown();
        return root;
    }

    _heapifyUp() {
        let idx = this.size() - 1;
        while (idx > 0) {
            let parent = Math.floor((idx - 1) / 2);
            if (this.compare(this.data[idx], this.data[parent]) >= 0) break;
            [this.data[idx], this.data[parent]] = [this.data[parent], this.data[idx]];
            idx = parent;
        }
    }

    _heapifyDown() {
        let idx = 0;
        while (true) {
            let left = 2 * idx + 1;
            let right = 2 * idx + 2;
            let smallest = idx;

            if (left < this.size() && this.compare(this.data[left], this.data[smallest]) < 0)
                smallest = left;
            if (right < this.size() && this.compare(this.data[right], this.data[smallest]) < 0)
                smallest = right;

            if (smallest === idx) break;
            [this.data[idx], this.data[smallest]] = [this.data[smallest], this.data[idx]];
            idx = smallest;
        }
    }
}

class Solution {
    findMostBookedRoom(totalRooms, meetings) {
        meetings.sort((a, b) => a[0] - b[0]);

        const freeRooms = new MinHeap((a, b) => a - b);
        for (let i = 0; i < totalRooms; i++) freeRooms.push(i);

        const busyRooms = new MinHeap((a, b) => {
            if (a[0] !== b[0]) return a[0] - b[0];
            return a[1] - b[1];
        });

        const count = Array(totalRooms).fill(0);

        for (const [start, end] of meetings) {
            const duration = end - start;

            while (busyRooms.size() && busyRooms.peek()[0] <= start) {
                freeRooms.push(busyRooms.pop()[1]);
            }

            if (freeRooms.size()) {
                const room = freeRooms.pop();
                busyRooms.push([end, room]);
                count[room]++;
            } else {
                const [freeTime, room] = busyRooms.pop();
                busyRooms.push([freeTime + duration, room]);
                count[room]++;
            }
        }

        let ans = 0;
        for (let i = 1; i < totalRooms; i++) {
            if (count[i] > count[ans]) ans = i;
        }
        return ans;
    }
}
